import{_ as e,a,b as d,c as r,d as o}from"./chunks/复制刷新令牌.IwW3dosg.js";import{_ as i,o as n,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"OneDrive チャンネルの追加","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/upload/onedrive.md","filePath":"ja-JP/upload/onedrive.md","lastUpdated":1781962217000}'),c={name:"ja-JP/upload/onedrive.md"};function p(h,t,b,m,f,g){return n(),s("div",null,[...t[0]||(t[0]=[l('<h1 id="onedrive-チャンネルの追加" tabindex="-1">OneDrive チャンネルの追加 <a class="header-anchor" href="#onedrive-チャンネルの追加" aria-label="Permalink to &quot;OneDrive チャンネルの追加&quot;">​</a></h1><p>OneDrive チャンネルは、Microsoft OneDrive を ImgBed の保存先として利用します。</p><h2 id="事前に用意するもの" tabindex="-1">事前に用意するもの <a class="header-anchor" href="#事前に用意するもの" aria-label="Permalink to &quot;事前に用意するもの&quot;">​</a></h2><table tabindex="0"><thead><tr><th>必要なもの</th><th>用途</th></tr></thead><tbody><tr><td>Microsoft アカウント</td><td>OneDrive とアプリ登録に使います</td></tr><tr><td>ImgBed ドメイン</td><td>OAuth コールバック URL に使います</td></tr><tr><td>App registration</td><td>Client ID と Client Secret を取得します</td></tr><tr><td>Refresh Token</td><td>長期アクセスに使います</td></tr></tbody></table><h2 id="microsoft-entra-id-を開く" tabindex="-1">Microsoft Entra ID を開く <a class="header-anchor" href="#microsoft-entra-id-を開く" aria-label="Permalink to &quot;Microsoft Entra ID を開く&quot;">​</a></h2><ol><li><code>portal.azure.com</code> を開きます。</li><li>上部検索で <code>Microsoft Entra ID</code> を探します。</li><li><code>App registrations</code> を開きます。</li><li><code>New registration</code> をクリックします。</li></ol><h2 id="アプリを登録する" tabindex="-1">アプリを登録する <a class="header-anchor" href="#アプリを登録する" aria-label="Permalink to &quot;アプリを登録する&quot;">​</a></h2><table tabindex="0"><thead><tr><th>項目</th><th>入力内容</th></tr></thead><tbody><tr><td>Name</td><td>例：<code>imgbed-onedrive</code></td></tr><tr><td>Supported account types</td><td>利用する OneDrive の種類に合わせて選択</td></tr><tr><td>Redirect URI type</td><td><code>Web</code></td></tr><tr><td>Redirect URI</td><td><code>https://あなたのドメイン/api/oauth/onedrive/callback</code></td></tr></tbody></table><p>個人 OneDrive だけなら個人 Microsoft アカウント向けを選びます。個人と組織の両方に対応したい場合は、両方を許可する種類を選びます。</p><p><img src="'+e+'" alt="OneDrive アプリ登録" loading="lazy"></p><p>登録後、<code>Application (client) ID</code> を控えます。組織アカウントで使う場合は <code>Directory (tenant) ID</code> も控えます。</p><p><img src="'+a+'" alt="Application ID と Tenant ID" loading="lazy"></p><h2 id="client-secret-を作成する" tabindex="-1">Client Secret を作成する <a class="header-anchor" href="#client-secret-を作成する" aria-label="Permalink to &quot;Client Secret を作成する&quot;">​</a></h2><ol><li><code>Certificates &amp; secrets</code> を開きます。</li><li><code>New client secret</code> をクリックします。</li><li>名前と有効期限を設定します。</li><li>作成後すぐに <code>Value</code> をコピーします。</li></ol><p><img src="'+d+'" alt="Client Secret" loading="lazy"></p><p>この値はあとから再表示できないため、必ず保存してください。</p><h2 id="microsoft-graph-権限" tabindex="-1">Microsoft Graph 権限 <a class="header-anchor" href="#microsoft-graph-権限" aria-label="Permalink to &quot;Microsoft Graph 権限&quot;">​</a></h2><p><code>API permissions</code> で Microsoft Graph の delegated permissions を追加します。</p><table tabindex="0"><thead><tr><th>権限</th><th>用途</th></tr></thead><tbody><tr><td><code>Files.ReadWrite.All</code></td><td>ファイルのアップロード、ディレクトリ作成、削除</td></tr><tr><td><code>offline_access</code></td><td>Refresh Token の取得</td></tr><tr><td><code>User.Read</code></td><td>アカウント情報と容量確認</td></tr></tbody></table><h2 id="imgbed-へ入力する" tabindex="-1">ImgBed へ入力する <a class="header-anchor" href="#imgbed-へ入力する" aria-label="Permalink to &quot;ImgBed へ入力する&quot;">​</a></h2><p>アップロード設定で <code>OneDrive</code> を選びます。</p><table tabindex="0"><thead><tr><th>項目</th><th>入力内容</th></tr></thead><tbody><tr><td>チャンネル名</td><td>例：<code>OneDrive Main</code></td></tr><tr><td>Client ID</td><td><code>Application (client) ID</code></td></tr><tr><td>Client Secret</td><td>作成した Secret の Value</td></tr><tr><td>Tenant ID</td><td>下表を参照</td></tr><tr><td>Refresh Token</td><td>まずは空欄</td></tr><tr><td>ルートディレクトリ</td><td>任意。通常は <code>imgbed</code></td></tr></tbody></table><p><img src="'+r+'" alt="OneDrive 設定" loading="lazy"></p><table tabindex="0"><thead><tr><th>利用アカウント</th><th>Tenant ID</th></tr></thead><tbody><tr><td>個人アカウント</td><td><code>consumers</code></td></tr><tr><td>個人 + 組織</td><td><code>common</code></td></tr><tr><td>特定組織のみ</td><td><code>Directory (tenant) ID</code></td></tr></tbody></table><h2 id="refresh-token-を取得する" tabindex="-1">Refresh Token を取得する <a class="header-anchor" href="#refresh-token-を取得する" aria-label="Permalink to &quot;Refresh Token を取得する&quot;">​</a></h2><ol><li>ImgBed で「Token を取得」をクリックします。</li><li>保存先に使う Microsoft アカウントでログインします。</li><li>権限を許可します。</li><li>コールバックページに表示された <code>Refresh Token</code> をコピーします。</li><li>ImgBed へ戻り、<code>Refresh Token</code> 欄に貼り付けます。</li></ol><p><img src="'+o+`" alt="Refresh Token" loading="lazy"></p><h2 id="クイック手順" tabindex="-1">クイック手順 <a class="header-anchor" href="#クイック手順" aria-label="Permalink to &quot;クイック手順&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>portal.azure.com を開く</span></span>
<span class="line"><span>-&gt; Microsoft Entra ID</span></span>
<span class="line"><span>-&gt; App registrations</span></span>
<span class="line"><span>-&gt; New registration</span></span>
<span class="line"><span>-&gt; Web コールバック URL を設定</span></span>
<span class="line"><span>-&gt; Application ID をコピー</span></span>
<span class="line"><span>-&gt; Client Secret を作成</span></span>
<span class="line"><span>-&gt; Microsoft Graph 権限を追加</span></span>
<span class="line"><span>-&gt; ImgBed に Client ID / Secret / Tenant ID を入力</span></span>
<span class="line"><span>-&gt; Token を取得</span></span>
<span class="line"><span>-&gt; Refresh Token を貼り付けて保存</span></span></code></pre></div>`,29)])])}const I=i(c,[["render",p]]);export{_ as __pageData,I as default};
